html:
{% set co = get_company_info(doc.company) %}
{% set co_addr = get_company_address(doc.company) %}

<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body {
  font-family: 'Inter', Arial, sans-serif;
  font-size: 11px;
  color: #1a1a1a;
  background: white;
  padding: 8px;
}
.ol-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  padding-bottom: 18px;
  border-bottom: 3px solid #0F2340;
  margin-bottom: 22px;
}
.ol-company-name {
  font-size: 20px;
  font-weight: 800;
  color: #0F2340;
  letter-spacing: 1.5px;
  text-transform: uppercase;
}
.ol-company-meta {
  font-size: 9.5px;
  color: #555;
  margin-top: 6px;
  line-height: 1.7;
}
.ol-doc-block { text-align: right; min-width: 200px; }
.ol-doc-type {
  font-size: 16px;
  font-weight: 800;
  color: #0D9488;
  text-transform: uppercase;
  letter-spacing: 2px;
}
.ol-doc-number {
  font-size: 12px;
  font-weight: 700;
  color: #0F2340;
  margin-top: 5px;
}
.ol-doc-meta {
  font-size: 9.5px;
  color: #555;
  margin-top: 5px;
  line-height: 1.8;
}
.ol-doc-meta b { color: #0F2340; }
.ol-section-label {
  font-size: 8.5px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.2px;
  color: #0D9488;
  margin-bottom: 6px;
}
.ol-two-col {
  display: flex;
  gap: 24px;
  margin-bottom: 18px;
}
.ol-box {
  flex: 1;
  background: #f6f8fd;
  border-left: 3px solid #0F2340;
  padding: 10px 14px;
}
.ol-box-title {
  font-size: 8px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #0D9488;
  margin-bottom: 5px;
}
.ol-box-name { font-size: 12px; font-weight: 700; color: #0F2340; }
.ol-box-meta { font-size: 9.5px; color: #555; margin-top: 3px; line-height: 1.6; }
.ol-logistics-bar {
  background: #f0fdfa;
  border: 1px solid #99f6e4;
  border-radius: 4px;
  padding: 8px 14px;
  margin-bottom: 18px;
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
  font-size: 9.5px;
  color: #555;
}
.ol-logistics-bar b { color: #0F2340; }
.ol-logistics-kpi {
  display: flex;
  flex-direction: column;
}
.ol-logistics-kpi span:first-child {
  font-size: 8px;
  text-transform: uppercase;
  letter-spacing: 0.8px;
  color: #0D9488;
  font-weight: 700;
}
.ol-logistics-kpi span:last-child {
  font-size: 12px;
  font-weight: 700;
  color: #0F2340;
}
table.ol-items {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 16px;
  font-size: 10.5px;
}
table.ol-items thead tr { background: #0F2340; color: #fff; }
table.ol-items thead th {
  padding: 8px 10px;
  font-size: 9.5px;
  font-weight: 600;
  letter-spacing: 0.4px;
}
table.ol-items tbody tr { border-bottom: 1px solid #e4e8f0; }
table.ol-items tbody tr:nth-child(even) { background: #f0fdfa; }
table.ol-items tbody td { padding: 7px 10px; vertical-align: top; }
.ol-confirmation {
  display: flex;
  gap: 30px;
  margin-top: 30px;
  padding-top: 18px;
  border-top: 1px solid #ddd;
}
.ol-sig-block { flex: 1; text-align: center; }
.ol-sig-line { border-bottom: 1px solid #aaa; height: 50px; margin-bottom: 5px; }
.ol-sig-label { font-size: 9px; color: #555; font-weight: 600; }
.ol-sig-sub { font-size: 8px; color: #999; margin-top: 3px; }
.ol-footer {
  display: flex;
  justify-content: space-between;
  margin-top: 20px;
  padding-top: 10px;
  border-top: 1px solid #ddd;
  font-size: 9px;
  color: #888;
}
.tr { text-align: right; }
.tc { text-align: center; }
</style>

<!-- HEADER -->
<div class="ol-header">
  <div>
    <div class="ol-company-name">{{ doc.company }}</div>
    <div class="ol-company-meta">
      {%- if co_addr %}{{ co_addr }}<br>{% endif %}
      {%- if co.phone %}{{ _("Tél") }}: {{ co.phone }}<br>{% endif %}
      {%- if co.email %}{{ co.email }}<br>{% endif %}
      {%- if co.tax_id %}{{ _("ICE") }} : {{ co.tax_id }}{% endif %}
    </div>
  </div>
  <div class="ol-doc-block">
    <div class="ol-doc-type">{{ _("Bon de Livraison") }}</div>
    <div class="ol-doc-number">{{ doc.name }}</div>
    <div class="ol-doc-meta">
      {{ _("Date") }} : <b>{{ frappe.format_date(doc.posting_date) }}</b><br>
      {%- if doc.lr_no %}
      {{ _("N° Transport") }} : <b>{{ doc.lr_no }}</b><br>
      {%- endif %}
      {%- if doc.custom_destination_zone %}
      {{ _("Zone") }} : <b>{{ doc.custom_destination_zone }}</b>
      {%- endif %}
    </div>
  </div>
</div>

<!-- CLIENT + DELIVERY ADDRESS -->
<div class="ol-two-col">
  <div class="ol-box">
    <div class="ol-box-title">{{ _("Client") }}</div>
    <div class="ol-box-name">{{ doc.customer_name }}</div>
    {%- if doc.address_display %}
    <div class="ol-box-meta">{{ doc.address_display | striptags | replace('\n', ', ') }}</div>
    {%- endif %}
    {%- if doc.contact_display %}
    <div class="ol-box-meta">{{ _("Contact") }} : {{ doc.contact_display }}</div>
    {%- endif %}
  </div>
  <div class="ol-box">
    <div class="ol-box-title">{{ _("Adresse de livraison") }}</div>
    {%- if doc.shipping_address %}
    <div class="ol-box-meta">{{ doc.shipping_address | striptags | replace('\n', ', ') }}</div>
    {%- else %}
    <div class="ol-box-meta" style="color:#aaa;font-style:italic">{{ _("Même adresse") }}</div>
    {%- endif %}
    {%- if doc.items %}
    <div class="ol-box-meta" style="margin-top:5px">{{ _("Entrepôt") }} : <b>{{ doc.items[0].warehouse }}</b></div>
    {%- endif %}
  </div>
</div>

<!-- LOGISTICS BAR (only if logistics fields filled) -->
{%- if doc.custom_total_weight_kg or doc.custom_total_volume_m3 or doc.custom_recommended_container %}
<div class="ol-logistics-bar">
  {%- if doc.custom_total_weight_kg %}
  <div class="ol-logistics-kpi">
    <span>{{ _("Poids total") }}</span>
    <span>{{ doc.custom_total_weight_kg | round(2) }} kg</span>
  </div>
  {%- endif %}
  {%- if doc.custom_total_volume_m3 %}
  <div class="ol-logistics-kpi">
    <span>{{ _("Volume total") }}</span>
    <span>{{ doc.custom_total_volume_m3 | round(3) }} m³</span>
  </div>
  {%- endif %}
  {%- if doc.custom_recommended_container %}
  <div class="ol-logistics-kpi">
    <span>{{ _("Transport recommandé") }}</span>
    <span>{{ doc.custom_recommended_container }}</span>
  </div>
  {%- endif %}
  {%- if doc.custom_assigned_container_load_plan %}
  <div class="ol-logistics-kpi">
    <span>{{ _("Plan de chargement") }}</span>
    <span>{{ doc.custom_assigned_container_load_plan }}</span>
  </div>
  {%- endif %}
</div>
{%- endif %}

<!-- ITEMS -->
<div class="ol-section-label">{{ _("Articles livrés") }}</div>
<table class="ol-items">
  <thead>
    <tr>
      <th class="tc" style="width:28px">#</th>
      <th style="width:110px">{{ _("Référence") }}</th>
      <th>{{ _("Désignation") }}</th>
      <th class="tc" style="width:52px">{{ _("Qté") }}</th>
      <th class="tc" style="width:38px">{{ _("U.") }}</th>
      <th style="width:120px">{{ _("Lot / Série") }}</th>
    </tr>
  </thead>
  <tbody>
    {%- for item in doc.items %}
    <tr>
      <td class="tc">{{ loop.index }}</td>
      <td>{{ item.item_code }}</td>
      <td>{{ item.item_name }}</td>
      <td class="tc" style="font-weight:700">{{ item.qty | int if item.qty == (item.qty | int) else item.qty }}</td>
      <td class="tc">{{ item.uom }}</td>
      <td style="font-size:9px;color:#777">
        {%- if item.batch_no %}{{ item.batch_no }}{%- endif %}
        {%- if item.serial_no %}{{ item.serial_no }}{%- endif %}
      </td>
    </tr>
    {%- endfor %}
  </tbody>
</table>

<!-- REF TO SO -->
{%- if doc.items and doc.items[0].against_sales_order %}
<div style="font-size:9px;color:#555;margin-bottom:18px">
  {{ _("Réf. commande") }} : <b>{{ doc.items[0].against_sales_order }}</b>
</div>
{%- endif %}

<!-- CONFIRMATION SIGNATURES -->
<div class="ol-confirmation">
  <div class="ol-sig-block">
    <div class="ol-sig-line"></div>
    <div class="ol-sig-label">{{ _("Expéditeur") }}</div>
    <div class="ol-sig-sub">{{ doc.company }}</div>
  </div>
  <div class="ol-sig-block">
    <div class="ol-sig-line"></div>
    <div class="ol-sig-label">{{ _("Transporteur") }}</div>
    <div class="ol-sig-sub">{{ _("Nom & Signature") }}</div>
  </div>
  <div class="ol-sig-block">
    <div class="ol-sig-line"></div>
    <div class="ol-sig-label">{{ _("Réceptionné par") }}</div>
    <div class="ol-sig-sub">{{ doc.customer_name }}</div>
  </div>
</div>

<!-- FOOTER -->
<div class="ol-footer">
  <div><b>{{ doc.company }}</b>{%- if co_addr %} · {{ co_addr }}{% endif %}</div>
  <div>{{ doc.name }} · {{ frappe.format_date(doc.posting_date) }}</div>
</div>
